def dark_table(df):
    cols  = df.columns.tolist()
    hcells = "".join(f'<th style="padding:8px 12px;text-align:left;color:#888;font-weight:600;font-size:10px;text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid #383838;">{c}</th>' for c in cols)
    body = ""
    for _, row in df.iterrows():
        dcells = "".join(f'<td style="padding:7px 12px;color:#ddd;border-bottom:1px solid #2a2a2a;">{v}</td>' for v in row.values)
        body += f'<tr>{dcells}</tr>'
    html = ('<div style="overflow-x:auto;margin:4px 0;">'
            '<table style="width:100%;border-collapse:collapse;font-family:Segoe UI,Arial;font-size:12px;">'
            f'<thead><tr style="background:#1a1a1a;">{hcells}</tr></thead>'
            f'<tbody>{body}</tbody>'
            '</table></div>')
    st.markdown(html, unsafe_allow_html=True)

# ═══════════════════════════════════════════════════════
# GREENWOOD
# ═══════════════════════════════════════════════════════
A_GW=165.4; a_GW=2.1; k_GW=0.88; NUM_E=12

ELECTRODE_SPACING = {
    "FLEX24":1.9,"FLEX26":1.9,"FLEX28":2.1,"FLEXSOFT":2.4,"CUSTOM":None
}

def freq_to_x(f):    return (1/a_GW)*math.log10(f/A_GW+k_GW)
def x_to_freq(x):    return A_GW*(10**(a_GW*x)-k_GW)
def x_to_d(x,cdl):  return cdl-x*cdl
def d_to_x(d,cdl):  return 1-d/cdl
def build_map(ae,ad,cdl,sp): return [x_to_freq(d_to_x(ad+(ae-e)*sp,cdl)) for e in range(1,NUM_E+1)]
def single_peak(f,e,cdl,sp): return build_map(e,x_to_d(freq_to_x(f),cdl),cdl,sp)
def two_peak(f,e1,a1,e2,a2,cdl,sp):
    d0=x_to_d(freq_to_x(f),cdl); dd=(a2/(a1+a2))*sp
    return build_map(e1,d0+dd if e2>e1 else d0-dd,cdl,sp)
def geometric_mean_multiple(maps):
    result=[]
    for values in zip(*maps):
        product=1
        for v in values: product*=v
        if product<0: result.append(float('nan'))
        else: result.append(product**(1/len(values)))
    return result
def mismatch(fm,rm):
    mm=[12*math.log2(abs(f)/r) for f,r in zip(fm,rm)]
    return mm,sum(abs(v) for v in mm)/len(mm)


