_COCHLEA_B64 = ""
_ELEC_FRAC = [[18.2, 45.8], [17.2, 30.0], [27.0, 15.7], [47.6, 7.9], [69.5, 8.6], [84.7, 17.7], [88.4, 32.0], [79.3, 44.1], [58.4, 47.3], [46.8, 38.9], [47.6, 26.6], [64.9, 23.3]]

def make_cochlea_html(map_freqs, ref_freqs=None, map_name="Map", width=500):
    import json as _j
    lbl = map_name.replace('"','').replace("'","")
    ELEC = _ELEC_FRAC
    iw, ih = 763, 1157
    h = round(width * ih / iw)

    def fcol(val):
        f=max(300,min(12000,abs(val)))
        t=(math.log10(f)-math.log10(300))/(math.log10(12000)-math.log10(300))
        s=[(0,(215,8,8)),(0.18,(248,108,0)),(0.35,(230,218,0)),
           (0.52,(12,188,12)),(0.70,(0,192,215)),(0.87,(12,60,238)),(1,(68,8,198))]
        for j in range(len(s)-1):
            if s[j][0]<=t<=s[j+1][0]:
                a=(t-s[j][0])/(s[j+1][0]-s[j][0])
                return f"rgb({int(s[j][1][0]+a*(s[j+1][1][0]-s[j][1][0]))}," \
                       f"{int(s[j][1][1]+a*(s[j+1][1][1]-s[j][1][1]))}," \
                       f"{int(s[j][1][2]+a*(s[j+1][1][2]-s[j][1][2]))})"
        return "rgb(68,8,198)"

    shadow = "0 0 3px #000,-1px -1px 0 #000,1px -1px 0 #000,-1px 1px 0 #000,1px 1px 0 #000"
    elec_html = ""
    for i in range(12):
        val = map_freqs[i]
        ref = ref_freqs[i] if ref_freqs else None
        if isinstance(val,float) and math.isnan(val): continue
        ex,ey = ELEC[i]
        col = fcol(val)
        map_t = f'<div style="font-size:10px;font-weight:700;color:{col};text-shadow:{shadow};white-space:nowrap;margin-bottom:1px;">{round(val)}</div>'
        dot   = f'<div style="width:19px;height:19px;border-radius:50%;background:radial-gradient(circle at 35% 35%,#fff,#c0c4d8);border:1.5px solid rgba(60,60,100,.6);display:flex;align-items:center;justify-content:center;margin:0 auto;box-shadow:0 1px 4px rgba(0,0,0,.4);"><span style="font-size:8px;font-weight:700;color:#111;">{i+1}</span></div>'
        ref_t = f'<div style="font-size:9px;font-weight:600;color:#ddd;text-shadow:{shadow};white-space:nowrap;margin-top:1px;">{round(ref)}</div>' if ref is not None else ""
        elec_html += f'<div style="position:absolute;left:{ex}%;top:{ey}%;transform:translate(-50%,-50%);text-align:center;line-height:1;">{map_t}{dot}{ref_t}</div>'

    ref_leg = '&nbsp;<span style="font-size:10px;color:#aaa;">&#9679; Reference</span>' if ref_freqs else ""
    return f"""<!DOCTYPE html><html><head><meta charset="utf-8">
<style>
html{{background:#1a1a1a!important;}}
*{{margin:0;padding:0;box-sizing:border-box;}}
body{{background:#1a1a1a!important;font-family:Arial,sans-serif;}}
#w{{position:relative;width:{width}px;height:{h}px;margin:0 auto;background:#1a1a1a;}}
#w img{{width:100%;height:100%;display:block;object-fit:fill;}}
#lg{{text-align:center;padding:4px 0 0;background:#1a1a1a;color:#ccc;}}
</style></head><body>
<div id="w"><img src="data:image/png;base64,{_COCHLEA_B64}" />{elec_html}</div>
<div id="lg"><span style="display:inline-block;width:22px;height:7px;background:linear-gradient(to right,#d40808,#0cbc0c,#0c3cee);border-radius:2px;vertical-align:middle;margin-right:4px;"></span><b style="font-size:11px;">{lbl}</b>{ref_leg}</div>
</body></html>"""

