def freq_chart(maps_dict, rm):
    pal=['#4da6ff','#ff6b6b','#69db7c','#da77f2','#ffd43b']
    fig=go.Figure()
    for i,(nm,fm) in enumerate(maps_dict.items()):
        c=pal[i%len(pal)]
        fig.add_trace(go.Scatter(
            x=list(range(1,13)),
            y=[v/1000 if not(isinstance(v,float) and math.isnan(v)) else None for v in fm],
            mode='lines+markers',name=nm,
            line=dict(color=c,width=2.5),
            marker=dict(size=7,color=c,line=dict(color='#333',width=1)),
            hovertemplate='<b>%{fullData.name}</b><br>E%{x}: <b>%{y:.2f} kHz</b><extra></extra>'))
    if rm:
        fig.add_trace(go.Scatter(
            x=list(range(1,13)),y=[v/1000 for v in rm],
            mode='lines+markers',name='Reference',
            line=dict(color='#aaa',width=2,dash='dot'),
            marker=dict(size=6,color='#aaa',symbol='diamond'),
            hovertemplate='<b>Reference</b><br>E%{x}: <b>%{y:.2f} kHz</b><extra></extra>'))
    fig.update_layout(
        template='plotly_dark',paper_bgcolor='#1e1e1e',plot_bgcolor='#252525',
        xaxis=dict(title=dict(text='Electrode',font=dict(family='Segoe UI',size=11,color='#ddd')),
                   tickmode='linear',tick0=1,dtick=1,gridcolor='rgba(255,255,255,0.07)',
                   color='#ddd',tickfont=dict(family='Segoe UI',size=10,color='#ddd'),
                   linecolor='#555',linewidth=1,mirror=True),
        yaxis=dict(title=dict(text='Frequency (kHz)',font=dict(family='Segoe UI',size=11,color='#ddd')),
                   gridcolor='rgba(255,255,255,0.07)',color='#ddd',
                   tickfont=dict(family='Segoe UI',size=10,color='#ddd'),
                   type='log',tickformat='.1f',linecolor='#555',linewidth=1,mirror=True),
        legend=dict(bgcolor='#2a2a2a',bordercolor='#555',borderwidth=1,
                    font=dict(family='Segoe UI',size=11,color='#ddd')),
        hovermode='x unified',height=360,margin=dict(l=10,r=10,t=20,b=10),
        font=dict(family='Segoe UI',color='#ddd'))
    return fig

def heatmap_fig(maps_dict, rm):
    names=list(maps_dict.keys())
    z_rows=[]
    for n in names:
        fm=maps_dict[n]; row=[]
        for f,r in zip(fm,rm):
            if isinstance(f,float) and math.isnan(f): row.append(None)
            else: row.append(12*math.log2(abs(f)/r))
        z_rows.append(row)
    z=np.array([[v if v is not None else float('nan') for v in row] for row in z_rows])
    am=float(np.nanmax(np.abs(z))) if not np.all(np.isnan(z)) else 1
    fig=go.Figure(go.Heatmap(
        z=z,x=[f"E{i}" for i in range(1,13)],y=names,
        colorscale=[[0,'#f44336'],[0.5,'#2a2a2a'],[1,'#2196f3']],
        zmid=0,zmin=-am,zmax=am,
        colorbar=dict(title=dict(text='Semitones',font=dict(family='Segoe UI',size=10,color='#ddd')),
                      tickfont=dict(family='Segoe UI',size=9,color='#ddd'),
                      outlinecolor='#555',outlinewidth=1,thickness=14,len=0.85),
        text=[[f"{v:+.1f}" if not math.isnan(v) else "N/A" for v in row] for row in z],
        texttemplate='%{text}',
        textfont=dict(family='Segoe UI',size=10,color='#ffffff'),
        hovertemplate='<b>%{y}</b><br>%{x}: <b>%{z:+.2f} semi</b><extra></extra>'))
    fig.update_layout(
        template='plotly_dark',paper_bgcolor='#1e1e1e',plot_bgcolor='#252525',
        xaxis=dict(tickfont=dict(family='Segoe UI',size=11,color='#ddd'),
                   side='top',tickcolor='#666',linecolor='#555'),
        yaxis=dict(tickfont=dict(family='Segoe UI',size=11,color='#ddd'),
                   autorange='reversed',tickcolor='#666',linecolor='#555'),
        height=max(200,75*len(names)+100),margin=dict(l=10,r=10,t=40,b=10),
        font=dict(family='Segoe UI',color='#ddd'))
    return fig

def mm_bar(mm_vals):
    cols=['#5cb85c' if abs(v)<1 else '#f0ad4e' if abs(v)<3 else '#f44336' for v in mm_vals]
    fig=go.Figure()
    fig.add_trace(go.Bar(
        x=[f"E{i}" for i in range(1,13)],y=mm_vals,
        marker_color=cols,marker_line=dict(color='rgba(255,255,255,0.1)',width=0.5),
        hovertemplate='<b>%{x}</b>: %{y:+.2f} semi<extra></extra>'))
    for yv,c,d in [(0,'rgba(255,255,255,0.4)','solid'),
                   (1,'rgba(92,184,92,0.5)','dot'),(-1,'rgba(92,184,92,0.5)','dot'),
                   (3,'rgba(244,67,54,0.5)','dot'),(-3,'rgba(244,67,54,0.5)','dot')]:
        fig.add_hline(y=yv,line_color=c,line_width=1.5,line_dash=d)
    fig.update_layout(
        template='plotly_dark',paper_bgcolor='#1e1e1e',plot_bgcolor='#252525',
        xaxis=dict(tickfont=dict(family='Segoe UI',size=10,color='#ddd'),
                   tickcolor='#666',linecolor='#555',gridcolor='rgba(255,255,255,0.06)'),
        yaxis=dict(title=dict(text='Mismatch (semitones)',font=dict(family='Segoe UI',size=10,color='#ddd')),
                   tickfont=dict(family='Segoe UI',size=9,color='#ddd'),
                   gridcolor='rgba(255,255,255,0.06)',zeroline=False,
                   linecolor='#555',linewidth=1,mirror=True),
        height=260,margin=dict(l=10,r=10,t=10,b=10),
        font=dict(family='Segoe UI',color='#ddd'),bargap=0.3)
    return fig


